import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const ProfilePage = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState('info');

  const mockMyProducts = [
    { id: 1, name: 'Iphone 11 cũ', price: 5000000, status: 'Đang hiện', date: '20/02/2026' },
    { id: 2, name: 'Xe Wave Alpha', price: 12000000, status: 'Đã bán', date: '18/02/2026' },
  ];

  const mockOrders = [
    { id: 'DH001', item: 'Laptop Dell', total: 8500000, status: 'Đang giao', color: 'text-primary' },
    { id: 'DH002', item: 'Chuột Logitech', total: 250000, status: 'Hoàn thành', color: 'text-success' },
  ];

  useEffect(() => {
    const userInfo = localStorage.getItem('userInfo');
    if (userInfo) {
      setUser(JSON.parse(userInfo));
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  if (!user) return null;

  return (
    <div className="container py-4">
      
      {/* HEADER LOGO QUAY VỀ TRANG CHỦ */}
      <header className="d-flex align-items-center mb-4 pb-3 border-bottom">
        <h2 
          className="fw-bold text-chotot m-0" // Dùng màu vàng Chợ Tốt luôn cho đồng bộ
          style={{ cursor: 'pointer', fontFamily: 'Arial, sans-serif' }} 
          onClick={() => navigate('/')}
          title="Quay về trang chủ"
        >
          HaiHand
        </h2>
        <span className="ms-3 text-muted" style={{borderLeft: '1px solid #ccc', paddingLeft: '15px'}}>
          Trang Cá Nhân
        </span>
      </header>

      <div className="row">
        {/* CỘT TRÁI: MENU */}
        <div className="col-md-3 mb-4">
          <div className="card border-0 shadow-sm">
            <div className="card-body text-center border-bottom">
              <div className="rounded-circle bg-chotot d-flex align-items-center justify-content-center mx-auto mb-2" style={{width: '60px', height: '60px', fontSize: '24px'}}>
                {user.name.charAt(0).toUpperCase()}
              </div>
              <h5 className="mb-0">{user.name}</h5>
              <small className="text-muted">Thành viên HaiHand</small>
            </div>
            <div className="list-group list-group-flush">
              <button className={`list-group-item list-group-item-action ${activeTab === 'info' ? 'bg-warning text-dark fw-bold' : ''}`} onClick={() => setActiveTab('info')}>👤 Thông tin cá nhân</button>
              <button className={`list-group-item list-group-item-action ${activeTab === 'products' ? 'bg-warning text-dark fw-bold' : ''}`} onClick={() => setActiveTab('products')}>📋 Quản lý tin đăng</button>
              <button className={`list-group-item list-group-item-action ${activeTab === 'orders' ? 'bg-warning text-dark fw-bold' : ''}`} onClick={() => setActiveTab('orders')}>📦 Đơn mua & Trạng thái</button>
              <button className={`list-group-item list-group-item-action ${activeTab === 'wallet' ? 'bg-warning text-dark fw-bold' : ''}`} onClick={() => setActiveTab('wallet')}>💰 Ví HaiHand (Mới)</button>
              <button className="list-group-item list-group-item-action text-danger" onClick={handleLogout}>🚪 Đăng xuất</button>
            </div>
          </div>
        </div>

        {/* CỘT PHẢI: NỘI DUNG */}
        <div className="col-md-9">
          <div className="card border-0 shadow-sm h-100">
            <div className="card-body">
              
              {activeTab === 'info' && (
                <div>
                  <h4 className="fw-bold mb-4">Hồ sơ của tôi</h4>
                  <div className="mb-3"><label className="form-label">Họ và tên</label><input type="text" className="form-control" defaultValue={user.name} /></div>
                  <div className="mb-3"><label className="form-label">Email</label><input type="text" className="form-control" defaultValue={user.email} disabled /></div>
                  <div className="mb-3"><label className="form-label">SĐT</label><input type="text" className="form-control" defaultValue="0987654321" /></div>
                  <div className="mb-3"><label className="form-label">Địa chỉ</label><input type="text" className="form-control" defaultValue="TP. Hồ Chí Minh" /></div>
                  <button className="btn btn-chotot mt-2">Lưu thay đổi</button>
                </div>
              )}

              {activeTab === 'products' && (
                <div>
                  <h4 className="fw-bold mb-4">Tin đăng của tôi</h4>
                  {mockMyProducts.map(prod => (
                    <div key={prod.id} className="d-flex justify-content-between align-items-center border-bottom py-3">
                      <div><h6 className="mb-1">{prod.name}</h6><span className="text-danger fw-bold">{prod.price.toLocaleString()} đ</span><br/><small className="text-muted">Ngày đăng: {prod.date}</small></div>
                      <div className="text-end"><span className={`badge ${prod.status === 'Đã bán' ? 'bg-secondary' : 'bg-success'}`}>{prod.status}</span></div>
                    </div>
                  ))}
                </div>
              )}

              {activeTab === 'orders' && (
                <div>
                  <h4 className="fw-bold mb-4">Lịch sử mua hàng</h4>
                  <table className="table">
                    <thead><tr><th>Mã đơn</th><th>Sản phẩm</th><th>Tổng tiền</th><th>Trạng thái</th></tr></thead>
                    <tbody>
                      {mockOrders.map(order => (
                        <tr key={order.id}><td>#{order.id}</td><td>{order.item}</td><td>{order.total.toLocaleString()} đ</td><td className={`fw-bold ${order.color}`}>{order.status}</td></tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}

               {activeTab === 'wallet' && (
                <div className="text-center py-5">
                   <div style={{fontSize: '50px'}}>💰</div>
                   <h3 className="mt-3">Số dư ví: <span className="text-chotot">0 đ</span></h3>
                   <button className="btn btn-chotot px-4">Nạp tiền ngay</button>
                </div>
              )}

            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;
